// The Agent node always wraps its result in { output: "..." }.
// The LLM puts a JSON string inside that field.
// This node unwraps it so the workflow returns { output, redirect } at the top level.

const raw = $input.first().json.output ?? '';

let parsed;
try {
  // The LLM may return a plain JSON string or wrap it in markdown code fences
  const clean = raw
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/```\s*$/i, '')
    .trim();
  parsed = JSON.parse(clean);
} catch (_) {
  // If parsing fails, treat the whole string as the output text
  parsed = { output: raw, redirect: '/' };
}

return [{
  json: {
    output: parsed.output ?? raw,
    redirect: parsed.redirect ?? '/'
  }
}];
